http:response.http:headers:
#[output application/java --- {
					"Access-Control-Allow-Origin": "*",
					"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
					"Access-Control-Allow-Headers": "Content-Type, Authorization"
				}]

db:select.db:input-parameters:
#[output application/java --- {
					studentId: ((attributes.queryParams default {}).studentId default '') as String,
					evalStatus: ((attributes.queryParams default {}).status default '') as String
				}]

db:insert.db:input-parameters:
#[output application/java --- using (b = payload default {}) {
					id: vars.newEvalId,
					studentId: b.studentId,
					courseCode: b.courseCode,
					comments: b.comments default null
				}]

db:update.db:input-parameters:
#[output application/java --- using (cur = vars.evalRow, p = vars.putBody default {}) {
	id: attributes.uriParams.evaluationId,
	status: p.status default cur.status,
	score: p.score default cur.score,
	comments: p.comments default cur.comments
}]
